#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[1] - y[1];
}
int main() {
    int n;
    scanf("%d", &n);
    int classes[n][2];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &classes[i][0], &classes[i][1]);
    }
    qsort(classes, n, sizeof(classes[0]), compare);
    int count = 1;
    int last = classes[0][1];
    for (int i = 1; i < n; i++) {
        if (classes[i][0] >= last) {
            count++;
            last = classes[i][1];
        }
    }
    printf("%d\n", count);
    return 0;
}

