using namespace std;
bool compare(int a[], int b[]) {
    return a[1] < b[1];
}
int main() {
    int n;
    cin >> n;
    int classes[n][2];
    for (int i = 0; i < n; i++) {
        cin >> classes[i][0] >> classes[i][1];
    }
    sort(classes, classes + n, compare);
    int count = 1;
    int last = classes[0][1];
    for (int i = 1; i < n; i++) {
        if (classes[i][0] >= last) {
            count++;
            last = classes[i][1];
        }
    }
    cout << count << endl;
    return 0;
}

